dir:














































































declare @unitName nvarchar(1023)
select @unitName = case when @@language = 'v' then ten_dvcs else ten_dvcs2 end from dmdvcs where ma_dvcs = @@unit
select 'this._unitCode=''' + @@unit + ''';this._unitName=''' + replace(replace(isnull(@unitName, ''), '\', '\\'), '''', '\''') + '''; active$FormVoucherBook(this);' as message
return







select 'close$FormVoucherBook(this);' as message
return







select 'init$FormVoucherBook(this)' as message
return







declare @$exists nvarchar(512), @$recordHasBeenChanged nvarchar(512), @$deleteConflict nvarchar(512), @$emptySerial nvarchar(512), @$emptyInvoiceType nvarchar(512)
select @$exists = case when @@language = 'v' then N'Mã quyển <span class="Highlight">%s</span> đã có hoặc lồng nhau trong khai báo phát hành hóa đơn.' else N'The book voucher <span class="Highlight">%s</span> is invalid or already exists.' end
select @$deleteConflict = case when @@language = 'v' then N'Mã quyển <span class="Highlight">%s</span> đã phát sinh, không thể xóa được.' else N'Cannot delete the voucher book <span class="Highlight">%s</span>. It has already been used.' end
select @$recordHasBeenChanged = case when @@language = 'v' then N'Mã quyển <span class="Highlight">%s</span> đã được sửa hoặc xóa bởi người sử dụng khác.' else N'The book voucher <span class="Highlight">%s</span> has been modified or deleted by another user.' end
select @$emptySerial = case when @@language = 'v' then N'Trường <span class="Highlight">Ký hiệu</span> chưa nhập hoặc giá trị nhập không hợp lệ.' else N'Field <span class="Highlight">Series</span> must not be blank or has invalid value.' end
select @$emptyInvoiceType = case when @@language = 'v' then N'Trường <span class="Highlight">Loại hóa đơn</span> chưa nhập hoặc giá trị nhập không hợp lệ.' else N'Field <span class="Highlight">Invoice Type</span> must not be blank or has invalid value.' end






        &CheckEmptyField;

if exists(select * from @@table where ((ma_nk like rtrim(@ma_nk) + '%') or rtrim(@ma_nk) like rtrim(ma_nk) + '%')) begin
  select 'ma_nk' as field, replace(@$exists, '%s', rtrim(@ma_nk)) as message
  return
end
select @datetime0 = getdate(), @datetime2 = getdate(), @user_id0 = @@userID, @user_id2 = @@userID






        &CheckEmptyField;

if not exists(select * from @@table where ma_nk = $ma_nk.OldValue) begin
  select 'ma_nk' as field, replace(@$recordHasBeenChanged, '%s', rtrim($ma_nk.OldValue)) as message
  return
end

if @ma_nk <> $ma_nk.OldValue begin
  if exists(select * from @@table where ((ma_nk like rtrim(@ma_nk) + '%') or rtrim(@ma_nk) like rtrim(ma_nk) + '%') and ma_nk <> $ma_nk.OldValue) begin
    select 'ma_nk' as field, replace(@$exists, '%s', rtrim(@ma_nk)) as message
    return
  end
end







update @@table set datetime2 = getdate(), user_id2 = @@userID where ma_nk = @ma_nk







      &OutlineEntry;

function active$FormVoucherBook(f) {
  f.add_onResponseComplete(on$FormVoucherBook$ResponseComplete);
  init$FormVoucherBook(f);
  changeLookupReadonly(f, 'lstuser', true);
}
function close$FormVoucherBook(f) {try {f.remove_onResponseComplete(on$FormVoucherBook$ResponseComplete)} catch (ex) {}}
function init$FormVoucherBook(f) {if (f._action == 'New') {f.setItemValues('ma_dvcs, ten_dvcs', [f._unitCode, f._unitName]);}}
function on$FormVoucherBook$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_nk');
      break;
    default:
      break;
  }
}

      &ScriptIrregular;



  &OutlineCss;
